import pandas as pd

# Access the review data
reviews_var = 'var_functions.query_db:18'
reviews_val = locals().get(reviews_var)

# Check if it's a string (file path) or already loaded data
if isinstance(reviews_val, str):
    if reviews_val.endswith('.json'):
        with open(reviews_val, 'r') as f:
            reviews_data = json.load(f)
    else:
        # It's a string representation of the preview
        reviews_data = json.loads(reviews_val) if reviews_val.strip() else []
else:
    reviews_data = reviews_val

# Access books data
books_var = 'var_functions.query_db:24'
books_val = locals().get(books_var)

if isinstance(books_val, str):
    if books_val.endswith('.json'):
        with open(books_val, 'r') as f:
            books_data = json.load(f)
    else:
        books_data = json.loads(books_val) if books_val.strip() else []
else:
    books_data = books_val

# Process data
result = []

# First find books with perfect 5.0 ratings
if reviews_data:
    for review in reviews_data:
        if review.get('avg_rating') == '5.0':
            pur_id = review.get('purchase_id', '')
            if pur_id:
                book_id = pur_id.replace('purchaseid_', 'bookid_')
                # Find in books data
                if books_data:
                    book_found = next((b for b in books_data if b.get('book_id') == book_id), None)
                    if book_found:
                        result.append(book_found)

print('__RESULT__:')
print(json.dumps(result, indent=2))

